const rawHandles = [
  'sama','AnthropicAI','demishassabis','ylecun',
  'karpathy','AndrewYNg','_jasonwei','giffmana',
  'swyx','simonw','jxnlco','abacaj',
  'trq212','noahzweben',
  'OpenAI','claudeai','GeminiApp','deepseek_ai','Kimi_Moonshot',
  'ClaudeDevs','OpenAIDevs',
  '_akhaliq','papers_daily','fchollet','geoffreyhinton',
  'drfeifei','kaifulee','AravSrinivas','GaryMarcus',
  'jeremyphoward','rowancheung','alliekmiller'
];
const seen = new Set();

// X handle 大小写不敏感，这里保留首次出现的写法并跳过重复项。
const handles = rawHandles.filter((handle) => {
  const key = handle.toLowerCase();
  if (seen.has(key)) return false;
  seen.add(key);
  return true;
});
return handles.map(h => ({ json: { handle: h } }));

const out = [];
const cutoff = Date.now() - 72 * 3600 * 1000;

for (const it of $input.all()) {
  let body = typeof it.json === 'string' ? it.json : (it.json?.data || it.json?.body || '');
  if (typeof body !== 'string' || !body.includes('<item>')) continue;

  const handle = ((it.json?.url || it.json?.requestUrl || '')).split('/').pop();
  const blocks = body.split('<item>').slice(1).map(s => '<item>' + s.split('</item>')[0]);

  for (const block of blocks) {
    const m = (re) => (block.match(re) || [, ''])[1];
    const title = m(/<title>(?:<!\[CDATA\[)?([\s\S]*?)(?:\]\]>)?<\/title>/);
    const link  = m(/<link>([\s\S]*?)<\/link>/);
    const desc  = m(/<description>(?:<!\[CDATA\[)?([\s\S]*?)(?:\]\]>)?<\/description>/);
    const pub   = m(/<pubDate>([\s\S]*?)<\/pubDate>/);
    const guid  = m(/<guid[^>]*>([\s\S]*?)<\/guid>/) || link;
    const ts = pub ? Date.parse(pub) : Date.now();
    if (ts < cutoff) continue;
    out.push({ json: {
      source: 'x',
      source_id: guid,
      title: title.replace(/<[^>]+>/g, '').slice(0, 200) || '(no title)',
      body: desc.replace(/<[^>]+>/g, '').trim(),
      post_url: link,
      link_url: null,
      author: '@' + (handle || ''),
      sub_or_handle: '@' + (handle || ''),
      score: 0,
      comment_count: null,
      published_at: new Date(ts).toISOString(),
      is_ai_relevant: true
    }});
  }
}
return out;
